    "tier": "core",
    "tags": [
      "stsvk_442",
      "slow",
      "intelligence",
      "regimes"
    ],
    "human": {
      "summary": "Slow intelligence regimes are operational modes where cognitive processes run at timescales far below human reaction speed, trading throughput for depth of integration and enabling forms of understanding inaccessible to fast processors.",
      "bullets": [
        "Slow intelligence can integrate across vastly more sensory and historical data before committing to action.",
        "Deliberation depth scales inversely with decision frequency in resource-bounded systems.",
        "Ecosystems and cultures are examples of slow intelligence regimes that outperform individual fast agents over long horizons."
      ]
    },
    "core": {
      "definitions": [
        {
          "term": "Slow Intelligence",
          "definition": "A cognitive regime where processing cycles are deliberately or structurally slower than environmental change rates, enabling deeper integration."
        },
        {
          "term": "Integration Depth",
          "definition": "The number of distinct information sources and temporal spans a decision process synthesizes before acting."
        }
      ],
      "invariants": [
        "Slower decision cycles permit wider causal integration at the cost of reduced responsiveness to fast-changing threats.",
        "No intelligence regime dominates all others across all environmental timescales.",
        "The optimal processing speed for a given task is determined by the autocorrelation time of the relevant environment variables."
      ],
      "claims": [
        "Biological evolution is a slow intelligence regime that has consistently outperformed faster adaptive systems over geological time.",
        "The bias toward speed in intelligence design reflects anthropocentric assumptions, not fundamental optimality.",
        "Slow intelligence regimes are more robust to noise because they effectively low-pass filter environmental signals."
      ],
      "examples": [
        "Coral reef ecosystems operate as slow intelligence systems, integrating temperature, chemistry, and biological signals over decades to centuries, producing adaptive responses that no individual organism could achieve at faster timescales.",
        "The Common Law legal tradition functions as a slow intelligence regime, accumulating judicial precedent over centuries to produce nuanced behavioral norms that outperform any single legislator's rapid rule-making."
      ],
      "nextActions": [
        "Explore dtu_441 for trans-human timescales, dtu_446 for intelligence without progress"
      ]
    },
