    "id": "dtu_446_intelligence_without_progress",
    "tier": "core",
    "tags": [
      "stsvk_446",
      "intelligence",
      "without",
      "progress"
    ],
    "human": {
      "summary": "Intelligence without progress examines cognitive systems that maintain high functionality while existing in a steady state, neither advancing nor declining, challenging the assumption that intelligence inherently drives toward novelty and growth.",
      "bullets": [
        "Many biological intelligences operate in stable equilibria for millions of years without directional progress.",
        "The conflation of intelligence with progress is a culturally specific assumption, not a logical necessity.",
        "Maintenance-mode intelligence may be the thermodynamically optimal long-term strategy for constrained environments."
      ]
    },
    "core": {
      "definitions": [
        {
          "term": "Steady-State Intelligence",
          "definition": "An intelligent system that actively maintains its current operational parameters without pursuing expansion or novelty."
        },
        {
          "term": "Progress Bias",
          "definition": "The unexamined assumption that intelligence must always be directed toward growth, discovery, or increasing complexity."
        }
      ],
      "invariants": [
        "An intelligence in steady state still expends energy to resist entropy, even when producing no novel outputs.",
        "Stability requires active maintenance; the absence of progress does not imply the absence of effort.",
        "No intelligent system can remain in perfect steady state indefinitely in a changing environment without some adaptive capacity."
      ],
      "claims": [
        "Most successful biological species operate as intelligence-without-progress systems for the majority of their evolutionary lifespan.",
        "The Western emphasis on progress as an inherent good has biased AI research toward growth-oriented architectures.",
        "A civilization capable of sustainable steady-state intelligence would outlast any civilization committed to perpetual growth."
      ],
      "examples": [
        "Horseshoe crabs (Limulus polyphemus) have maintained essentially unchanged morphology and behavior for over 450 million years, demonstrating that high-functioning intelligence-like adaptive systems can persist in steady state far longer than any progress-oriented civilization.",
        "Aboriginal Australian cultures maintained stable technological and social systems for over 60,000 years, representing the longest-running continuous civilization through deliberate emphasis on maintenance of knowledge and relationship to land rather than technological progress."
      ],
      "nextActions": [
        "Explore dtu_449 for intelligence without expansion, dtu_459 for eternal maintenance civilizations"
      ]
    },
    "machine": {
      "kind": "formal_model",
      "math": {
        "space": "X = (P, E_maint, Ω) where P is performance vector (fixed at steady-state P*), E_maint is maintenance energy expenditure, Ω is perturbation space of environmental changes",
        "variables": {
          "x": "state",
          "u": "control",
          "w": "noise",
          "θ": "parameters"
        },
        "dynamics": "ẋ = -∇V(x) + w(t) where V has a stable minimum at x* (steady state), and u(t) provides maintenance forcing: u = k·(x* - x) to counteract entropy-driven drift w(t)",
        "constraints": [
          "E_maint ≥ E_entropy: maintenance energy must exceed entropic degradation rate to sustain steady state",
          "||x - x*|| ≤ r: state must remain within basin of attraction of radius r around the steady-state fixed point"
        ],
        "potential": "V(x) = ½||x - x*||² ≥ 0, with x* the steady-state attractor; maintenance effort holds V near minimum against perturbations",
        "implication": "Steady-state intelligence is thermodynamically cheaper than growth-state intelligence: E_maint ~ O(n) for n components vs E_growth ~ O(n·log(n)) for expanding systems, yielding longer persistence per unit energy"
      },
      "primaryFormula": "Persistence(x*) = E_available / E_maint(x*) where E_maint(x*) = ∫ ||w(t)||dt is the cumulative perturbation that maintenance must counteract"
    },
