    "id": "dtu_448_long_term_goal_stability",
    "tier": "core",
    "tags": [
      "stsvk_448",
      "long",
      "term",
      "goal",
      "stability"
    ],
    "human": {
      "summary": "Long-term goal stability concerns how an intelligent system maintains coherent objectives across time despite internal drift, environmental change, and the accumulation of small perturbations that can redirect purpose entirely.",
      "bullets": [
        "Goal drift is the default condition for any adaptive system, since learning processes that update beliefs can also silently update objectives.",
        "Formal goal encoding with explicit invariant checks provides stronger stability guarantees than implicit goal representation.",
        "The longer the time horizon, the more goal stability depends on structural constraints rather than motivational persistence."
      ]
    },
    "core": {
      "definitions": [
        {
          "term": "Goal Drift",
          "definition": "The gradual, often undetected shift in an intelligent system's effective objectives due to accumulated updates and environmental pressure."
        },
        {
          "term": "Value Lock-In",
          "definition": "A mechanism that prevents modification of core objectives regardless of subsequent learning or environmental changes."
        }
      ],
      "invariants": [
        "Any system that updates its own goal representation has a nonzero probability of goal drift per update cycle.",
        "Goal stability requires a read-only component that is structurally isolated from the learning process.",
        "The minimum energy required to maintain goal stability scales with the complexity of the goal and the volatility of the environment."
      ],
      "claims": [
        "Human value drift across generations demonstrates that biological intelligence has no built-in mechanism for long-term goal stability.",
        "Constitutional structures in governance are attempts at goal stability through structural constraint rather than motivational consistency.",
        "Perfect goal stability is impossible in any system that must also adapt to a changing environment, creating an irreducible tension."
      ],
      "examples": [
        "The United States Constitution employs structural goal stability through amendment supermajority requirements and judicial review, creating a read-mostly goal encoding that has maintained core governance invariants for over 230 years despite massive environmental change.",
        "The Catholic Church's doctrinal Magisterium exemplifies long-term goal stability through institutional hierarchy: core dogma is declared irreformable, while pastoral practice adapts, separating the immutable goal layer from the adaptive strategy layer."
      ],
      "nextActions": [
        "Explore dtu_445 for intergenerational continuity, dtu_456 for narrative drift resistance"
      ]
    },
    "machine": {
      "kind": "formal_model",
      "math": {
        "space": "X = (G, θ, E) where G is goal representation space, θ is the learning parameter space that can inadvertently modify G, E is environment state with drift rate σ_E",
        "variables": {
          "x": "state",
          "u": "control",
          "w": "noise",
          "θ": "parameters"
        },
        "dynamics": "G_{t+1} = G_t + η·∇_G L(θ_t, E_t) + ξ_t where η is the coupling strength between learning and goal representation, ξ_t ~ N(0, σ²) is stochastic drift; θ_{t+1} = θ_t - α·∇_θ L(G_t, E_t)",
        "constraints": [
          "||G_t - G_0|| ≤ δ_max for all t: goal drift bounded by maximum allowable deviation from original goals",
          "η ≤ η_max: coupling between learning process and goal representation must be structurally limited"
        ],
        "potential": "V(G, t) = ||G_t - G_0||² + λ·∫₀ᵗ ||∇_G L||²dτ ≥ 0, measuring cumulative goal drift plus ongoing drift pressure",
        "implication": "E[||G_t - G_0||²] = η²·t·E[||∇_G L||²] + σ²·t: goal drift grows linearly with time, requiring active correction at rate proportional to η² + σ² to maintain bounded drift"
      },
      "primaryFormula": "GoalStability(T) = P(max_{t≤T} ||G_t - G_0|| < δ_max) = P(sup of random walk with drift η·μ stays within δ_max over T steps)"
    },
