    "id": "dtu_465_first_order_science_defined",
    "tier": "core",
    "tags": [
      "stsvk_465",
      "first",
      "order",
      "science",
      "defined"
    ],
    "human": {
      "summary": "First-order science is defined as knowledge that derives directly from constraint analysis of observable phenomena without requiring appeal to secondary interpretive frameworks, producing claims that are testable, falsifiable, and independent of theoretical fashion.",
      "bullets": [
        "First-order science operates on constraints and observables directly, without interposing metaphysical interpretive layers.",
        "It produces claims with clear empirical signatures that can be tested without first accepting a surrounding theoretical framework.",
        "The distinction between first-order and higher-order science clarifies which scientific claims are load-bearing and which are interpretive scaffolding."
      ]
    },
    "core": {
      "definitions": [
        {
          "term": "First-Order Science",
          "definition": "Scientific knowledge derived directly from constraint analysis of observables, requiring no interpretive framework beyond the constraints themselves."
        },
        {
          "term": "Interpretive Scaffolding",
          "definition": "Theoretical structures that aid human understanding but are not strictly necessary for the predictive or engineering content of a scientific claim."
        }
      ],
      "invariants": [
        "First-order scientific claims are invariant under changes in interpretive framework; they depend only on constraints and observables.",
        "Any claim that cannot be stated without reference to a specific interpretive framework is not first-order science.",
        "First-order science is strictly more durable than framework-dependent science because it survives paradigm shifts."
      ],
      "claims": [
        "Most of what is taught as settled science is actually a mixture of first-order results and interpretive scaffolding that is not clearly distinguished.",
        "The constraint framework provides a systematic method for extracting first-order content from any scientific theory.",
        "Disagreements between scientific schools usually occur at the interpretive level, not at the first-order level, and would dissolve if the distinction were made explicit."
      ],
      "examples": [
        "Newton's F=ma is first-order science: it states a constraint between force, mass, and acceleration that holds regardless of whether one interprets it through Cartesian mechanism, Leibnizian monadology, or modern field theory.",
        "The Copenhagen and many-worlds interpretations of quantum mechanics make identical first-order predictions (Born rule probabilities); the difference is entirely interpretive scaffolding with no empirical signature."
      ],
      "nextActions": [
        "Develop extraction procedures for separating first-order content from interpretive scaffolding in existing theories"
      ]
    },
    "machine": {
      "kind": "formal_model",
      "math": {
        "space": "S = S₁ × S₂ where S₁ is the first-order claim space (constraint-observable pairs) and S₂ is the interpretive scaffolding space",
        "variables": {
          "x": "state",
          "u": "control",
          "w": "noise",
          "θ": "parameters"
        },
        "dynamics": "ẋ₁ = F₁(x₁, observables) independent of x₂; ẋ₂ = F₂(x₁, x₂, framework) — first-order dynamics are autonomous",
        "constraints": [
          "∂predictions/∂x₂ = 0: no prediction depends on interpretive scaffolding variables",
          "rank(J₁) = dim(S₁): the first-order claim space is fully determined by constraints and observables alone"
        ],
        "potential": "V(theory) = ||∂predictions/∂scaffolding||² ≥ 0; V = 0 iff predictions are fully independent of interpretive choices",
        "implication": "V = 0 identifies the first-order core; claims with V > 0 are framework-dependent and should be labeled as interpretive, not empirical"
      },
      "primaryFormula": "first_order(claim) ⟺ ∀ frameworks F₁, F₂: predict(claim|F₁) = predict(claim|F₂)"
    },
