    "id": "dtu_476_knowledge_as_a_living_system",
    "tier": "core",
    "tags": [
      "stsvk_476",
      "knowledge",
      "as",
      "a",
      "living",
      "system"
    ],
    "human": {
      "summary": "Knowledge as a living system treats bodies of knowledge not as static archives but as dynamic entities that require active maintenance, updating, and pruning to remain viable, subject to the same constraint satisfaction requirements as biological organisms.",
      "bullets": [
        "Living knowledge systems must actively repair inconsistencies, integrate new information, and prune obsolete components.",
        "A knowledge system that is not actively maintained will accumulate contradictions and decay into incoherence.",
        "The analogy to living systems is precise: knowledge requires energy input (intellectual labor) to resist entropic degradation."
      ]
    },
    "core": {
      "definitions": [
        {
          "term": "Living Knowledge System",
          "definition": "A body of knowledge that is actively maintained, updated, and internally consistent, requiring ongoing intellectual labor to persist."
        },
        {
          "term": "Knowledge Entropy",
          "definition": "The tendency of unmaintained knowledge systems to accumulate contradictions, lose coherence, and become increasingly unreliable over time."
        }
      ],
      "invariants": [
        "All knowledge systems require ongoing maintenance energy; unmaintained knowledge degrades toward incoherence.",
        "A living knowledge system must have mechanisms for detecting and resolving internal contradictions.",
        "The maintenance cost of a knowledge system scales with its size and the rate of change in its subject matter."
      ],
      "claims": [
        "The distinction between living and dead knowledge is more important than the distinction between true and false knowledge.",
        "Most institutional knowledge bases are effectively dead systems that maintain the appearance of life through bureaucratic inertia.",
        "The constraint framework is designed as a living knowledge system with built-in self-repair mechanisms through constraint checking."
      ],
      "examples": [
        "Wikipedia functions as a living knowledge system: active editors detect contradictions (via citation-needed tags), integrate new discoveries (current events), and prune obsolete content (deletion discussions), maintaining coherence through continuous intellectual labor.",
        "Medieval monasteries maintained living knowledge systems through active copying, commentary, and cross-referencing of manuscripts; when monasteries were dissolved, the knowledge systems died — not because the manuscripts were destroyed, but because the maintenance labor ceased."
      ],
      "nextActions": [
        "Design self-repair mechanisms for the constraint framework; estimate maintenance labor requirements"
      ]
    },
    "machine": {
      "kind": "formal_model",
      "math": {
        "space": "K = (claims, links, timestamps) with coherence function η: K → [0,1] and entropy rate H: K × T → R≥0",
        "variables": {
          "x": "state",
          "u": "control",
          "w": "noise",
          "θ": "parameters"
        },
        "dynamics": "dη/dt = -H(K) + M(t) where H is knowledge entropy rate and M(t) is maintenance labor input at time t",
        "constraints": [
          "M(t) ≥ H(K): maintenance labor must exceed entropy rate to prevent coherence decay",
          "∀ contradictions (c_i, c_j) ∈ K: resolution_time(c_i, c_j) ≤ T_max — contradictions must be resolved within bounded time"
        ],
        "potential": "V(K) = (1 - η(K))² + |unresolved_contradictions(K)| ≥ 0; measures knowledge system health deficit",
        "implication": "M(t) > H(K) ∀t ⟹ η(K, t) → 1: sustained maintenance labor drives coherence to maximum — the knowledge system lives"
      },
      "primaryFormula": "living(K) ⟺ dη/dt ≥ 0 ⟺ M(t) ≥ H(K) — a knowledge system is alive iff maintenance exceeds entropy"
    },
